module data_control(
    input [15:0] data_in,
    input [3:0] control_in,
    output [15:0] data_out,
    output [3:0] control_out
);

  wire _n01 = data_in[0] ^ 1[0];
  wire _c01 = data_in[0] & 1[0];
  wire _n02 = data_in[1] ^ 1[1] ^ _c01;
  wire _c02 = (data_in[1] & 1[1]) | (data_in[1] & _c01) | (1[1] & _c01);
  wire _n03 = data_in[2] ^ 1[2] ^ _c02;
  wire _c03 = (data_in[2] & 1[2]) | (data_in[2] & _c02) | (1[2] & _c02);
  wire _n04 = data_in[3] ^ 1[3] ^ _c03;
  wire _c04 = (data_in[3] & 1[3]) | (data_in[3] & _c03) | (1[3] & _c03);
  assign data_out = {_n01, _n02, _n03, _n04};
assign control_out = control_in << 1;

endmodule
